import Foundation

func solve(nums: Array<Int64>, k: Int64) -> Int64 {
    let sortedNums = nums.sorted()
    let n = sortedNums.count
    var minRemovals = Int64.max

    for i in 0..<n {
        let minVal = sortedNums[i]
        let maxValThreshold = minVal * k

        var left = i
        var right = n - 1
        var bestJ = i

        while left <= right {
            let mid = left + (right - left) / 2
            if sortedNums[mid] <= maxValThreshold {
                bestJ = mid
                left = mid + 1
            } else {
                right = mid - 1
            }
        }

        let removals = Int64(n - (bestJ - i + 1))
        if removals < minRemovals {
            minRemovals = removals
        }
    }

    return minRemovals
}
